changeSet.sql:
CREATE TABLE damage_types (
    id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    code        varchar(60) NOT NULL,
    name_engloc text        NULL,
    name_rusloc text        NOT NULL,
    homebrew_id uuid        NULL REFERENCES homebrew_packages(id),
    is_unique   boolean     NOT NULL DEFAULT false,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now()
);
CREATE UNIQUE INDEX uq_damage_types_code_system ON damage_types (code) WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_damage_types_code_owner ON damage_types (code, homebrew_id);

CREATE TABLE item_rarities (
    id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    code        varchar(60) NOT NULL,
    name_engloc text        NULL,
    name_rusloc text        NOT NULL,
    homebrew_id uuid        NULL REFERENCES homebrew_packages(id),
    is_unique   boolean     NOT NULL DEFAULT false,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now()
);
CREATE UNIQUE INDEX uq_item_rarities_code_system ON item_rarities (code) WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_item_rarities_code_owner ON item_rarities (code, homebrew_id);

CREATE TABLE equipment_slots (
    id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    code        varchar(60) NOT NULL,
    name_engloc text        NULL,
    name_rusloc text        NOT NULL,
    homebrew_id uuid        NULL REFERENCES homebrew_packages(id),
    is_unique   boolean     NOT NULL DEFAULT false,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now()
);
CREATE UNIQUE INDEX uq_equipment_slots_code_system ON equipment_slots (code) WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_equipment_slots_code_owner ON equipment_slots (code, homebrew_id);

CREATE TABLE creature_sizes (
    id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    code        varchar(60) NOT NULL,
    name_engloc text        NULL,
    name_rusloc text        NOT NULL,
    homebrew_id uuid        NULL REFERENCES homebrew_packages(id),
    is_unique   boolean     NOT NULL DEFAULT false,
    created_at  timestamptz NOT NULL DEFAULT now(),
    updated_at  timestamptz NOT NULL DEFAULT now()
);
CREATE UNIQUE INDEX uq_creature_sizes_code_system ON creature_sizes (code) WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_creature_sizes_code_owner ON creature_sizes (code, homebrew_id);

INSERT INTO damage_types (code, name_rusloc, name_engloc) VALUES ('SLASHING', 'Рубящий', 'Slashing'), ('PIERCING', 'Колющий', 'Piercing'), ('BLUDGEONING', 'Дробящий', 'Bludgeoning'), ('FIRE', 'Огонь', 'Fire'), ('COLD', 'Холод', 'Cold'), ('LIGHTNING', 'Электричество', 'Lightning'), ('POISON', 'Яд', 'Poison'), ('NECROTIC', 'Некротический', 'Necrotic'), ('RADIANT', 'Излучение', 'Radiant'), ('PSYCHIC', 'Психический', 'Psychic'), ('FORCE', 'Силовое поле', 'Force'), ('THUNDER', 'Звук', 'Thunder'), ('ACID', 'Кислота', 'Acid');
INSERT INTO item_rarities (code, name_rusloc, name_engloc) VALUES ('COMMON', 'Обычный', 'Common'), ('UNCOMMON', 'Необычный', 'Uncommon'), ('RARE', 'Редкий', 'Rare'), ('VERY_RARE', 'Очень редкий','Very Rare'), ('LEGENDARY', 'Легендарный', 'Legendary');
INSERT INTO equipment_slots (code, name_rusloc, name_engloc) VALUES ('HEAD', 'Голова', 'Head'), ('CHEST', 'Торс', 'Chest'), ('LEGS', 'Ноги', 'Legs'), ('FEET', 'Ступни', 'Feet'), ('MAIN_HAND', 'Основная рука', 'Main Hand'), ('OFF_HAND', 'Вторая рука', 'Off Hand'), ('RING_LEFT', 'Кольцо (левое)', 'Ring (Left)'), ('RING_RIGHT', 'Кольцо (правое)', 'Ring (Right)'), ('NECK', 'Шея', 'Neck'), ('CLOAK', 'Плащ', 'Cloak');
INSERT INTO creature_sizes (code, name_rusloc, name_engloc) VALUES ('TINY', 'Крошечный', 'Tiny'), ('SMALL', 'Маленький', 'Small'), ('MEDIUM', 'Средний', 'Medium'), ('LARGE', 'Большой', 'Large'), ('HUGE', 'Огромный', 'Huge'), ('GARGANTUAN', 'Громадный', 'Gargantuan');

ALTER TABLE stat_types ADD COLUMN code varchar(60) NULL;

-- Match the six system abilities by their stable seed ids. Names are not reliable
-- here: migration 031 re-localised them from Russian (СИЛ/ЛОВ/...) to English
-- (Strength/Dexterity/...), so matching on name finds nothing.
UPDATE stat_types SET code = 'STRENGTH'     WHERE id = 'a0000000-0000-0000-0000-000000000001';
UPDATE stat_types SET code = 'DEXTERITY'    WHERE id = 'a0000000-0000-0000-0000-000000000002';
UPDATE stat_types SET code = 'CONSTITUTION' WHERE id = 'a0000000-0000-0000-0000-000000000003';
UPDATE stat_types SET code = 'INTELLIGENCE' WHERE id = 'a0000000-0000-0000-0000-000000000004';
UPDATE stat_types SET code = 'WISDOM'       WHERE id = 'a0000000-0000-0000-0000-000000000005';
UPDATE stat_types SET code = 'CHARISMA'     WHERE id = 'a0000000-0000-0000-0000-000000000006';

-- Fallback for any non-system rows (custom/homebrew stats) so the NOT NULL holds.
UPDATE stat_types SET code = upper(regexp_replace(name, '\s+', '_', 'g')) WHERE code IS NULL;

ALTER TABLE stat_types ALTER COLUMN code SET NOT NULL;

CREATE UNIQUE INDEX uq_stat_types_code_system ON stat_types (code) WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_stat_types_code_owner ON stat_types (code, homebrew_id);

ALTER TABLE item_types ADD COLUMN slot_id        uuid NULL REFERENCES equipment_slots(id);
ALTER TABLE item_types ADD COLUMN damage_type_id uuid NULL REFERENCES damage_types(id);

UPDATE item_types t SET slot_id =
    (SELECT s.id FROM equipment_slots s WHERE s.code = t.slot AND s.homebrew_id IS NULL);
UPDATE item_types t SET damage_type_id =
    (SELECT d.id FROM damage_types d WHERE d.code = t.damage_type AND d.homebrew_id IS NULL)
    WHERE t.damage_type IS NOT NULL;

ALTER TABLE item_types ALTER COLUMN slot_id SET NOT NULL;
ALTER TABLE item_types DROP COLUMN slot;
ALTER TABLE item_types DROP COLUMN damage_type;

ALTER TABLE item_templates ADD COLUMN rarity_id      uuid NULL REFERENCES item_rarities(id);
ALTER TABLE item_templates ADD COLUMN damage_type_id uuid NULL REFERENCES damage_types(id);

UPDATE item_templates t SET rarity_id =
    (SELECT r.id FROM item_rarities r WHERE r.code = t.rarity AND r.homebrew_id IS NULL)
    WHERE t.rarity IS NOT NULL;
UPDATE item_templates t SET damage_type_id =
    (SELECT d.id FROM damage_types d WHERE d.code = t.damage_type AND d.homebrew_id IS NULL)
    WHERE t.damage_type IS NOT NULL;

ALTER TABLE item_templates DROP COLUMN rarity;
ALTER TABLE item_templates DROP COLUMN damage_type;

ALTER TABLE skills ADD COLUMN damage_type_id uuid NULL REFERENCES damage_types(id);
UPDATE skills t SET damage_type_id =
    (SELECT d.id FROM damage_types d WHERE d.code = t.damage_type AND d.homebrew_id IS NULL)
    WHERE t.damage_type IS NOT NULL;
ALTER TABLE skills DROP COLUMN damage_type;

ALTER TABLE enchantment_types ADD COLUMN damage_type_id uuid NULL REFERENCES damage_types(id);
UPDATE enchantment_types t SET damage_type_id =
    (SELECT d.id FROM damage_types d WHERE d.code = t.damage_type AND d.homebrew_id IS NULL)
    WHERE t.damage_type IS NOT NULL;
ALTER TABLE enchantment_types DROP COLUMN damage_type;

ALTER TABLE item_instances ADD COLUMN slot_id uuid NULL REFERENCES equipment_slots(id);
UPDATE item_instances t SET slot_id =
    (SELECT s.id FROM equipment_slots s WHERE s.code = t.slot AND s.homebrew_id IS NULL)
    WHERE t.slot IS NOT NULL;
ALTER TABLE item_instances DROP COLUMN slot;
